<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; $esEdicion=is_array($seccion); ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Ubicación física</span><h1><?= $esEdicion?'Editar sección':'Nueva sección' ?></h1><p>Las secciones ayudan a ubicar físicamente cada pieza del inventario.</p></div><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/secciones')) ?>">Volver</a></section><?php if(!empty($errores)): ?><div class="alerta alerta--error"><ul><?php foreach($errores as $error): ?><li><?= Sanitizer::html($error) ?></li><?php endforeach; ?></ul></div><?php endif; ?><form class="card form-wide" method="POST" action="<?= Sanitizer::html(Url::ruta($esEdicion?'/secciones/actualizar/'.$seccion['id_seccion']:'/secciones/guardar')) ?>"><?= Csrf::campo() ?><div class="form-grid"><div class="form-group"><label>Código</label><input name="codigo" maxlength="30" required value="<?= Sanitizer::html($seccion['codigo'] ?? '') ?>"></div><div class="form-group"><label>Nombre</label><input name="nombre_seccion" required value="<?= Sanitizer::html($seccion['nombre_seccion'] ?? '') ?>"></div></div><div class="form-group"><label>Descripción</label><textarea name="descripcion" rows="3"><?= Sanitizer::html($seccion['descripcion'] ?? '') ?></textarea></div><label class="check-line"><input type="checkbox" name="activo" value="1" <?= (int)($seccion['activo'] ?? 1)===1?'checked':'' ?>> Activa</label><div class="form-actions"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/secciones')) ?>">Cancelar</a><button class="btn">Guardar</button></div></form></main>
